export const aiValidateQuestResponseScoreMin = 0;
export const aiValidateQuestResponseScoreMax = 100;

export const AiValidateQuestResponse = zod.object({
  score: zod
    .number()
    .min(aiValidateQuestResponseScoreMin)
    .max(aiValidateQuestResponseScoreMax),
  status: zod.enum(["approved", "needs_work", "rejected"]),
  summary: zod.string(),
  issues: zod.array(
    zod.object({
      severity: zod.enum(["info", "warning", "error"]),
      field: zod.string(),
      message: zod.string(),
    }),
  ),
  suggestions: zod.array(zod.string()),
});
